"""Ledger model for Ledgerly platform."""
from dataclasses import dataclass, field
from decimal import Decimal
from datetime import datetime
from typing import List, Optional


@dataclass
class LedgerEntry:
    """Represents an internal ledger entry for a settled transaction."""
    entry_id: str
    transaction_id: str
    merchant_id: str
    gross_amount: Decimal
    fee_amount: Decimal
    net_amount: Decimal
    entry_date: str  # YYYY-MM-DD
    created_at: datetime = field(default_factory=datetime.utcnow)


@dataclass
class DailyLedgerSummary:
    """Aggregated daily ledger data for a merchant."""
    merchant_id: str
    date: str  # YYYY-MM-DD
    entries: List[LedgerEntry] = field(default_factory=list)

    @property
    def total_gross(self) -> Decimal:
        """Sum of gross amounts from all entries."""
        return sum((e.gross_amount for e in self.entries), Decimal("0.00"))

    @property
    def total_fees(self) -> Decimal:
        """Sum of fees from all entries."""
        return sum((e.fee_amount for e in self.entries), Decimal("0.00"))

    @property
    def total_net(self) -> Decimal:
        """Sum of net amounts from all entries."""
        return sum((e.net_amount for e in self.entries), Decimal("0.00"))

    @property
    def entry_count(self) -> int:
        return len(self.entries)

